```class Solution {
public:
    int bestClosingTime(string customers) {
        int n = customers.size();
        int totalY = 0, prefixY = 0, res = 0, minPenalty = n;
        for (int i = 0; i < n; i++) {
            if (customers[i] == 'Y') totalY++;
        }
        for (int i = 0; i < n; i++) {
            int penalty = i - prefixY + (totalY - prefixY);
            if (penalty < minPenalty) {
                minPenalty = penalty;
                res = i;
            }
            if (customers[i] == 'Y') prefixY++;
        }
        return res;
    }
};
